var raw = $input.first().json;
var qs = raw.query || raw;
var tenantId = String(qs.tenantId || '').replace(/[^a-f0-9-]/gi, '').substring(0, 36);
var channel = ['telephone', 'email', 'web'].includes(qs.channel) ? qs.channel : null;
var minNote = parseInt(qs.minNote) || 0;
var limit = Math.min(parseInt(qs.limit) || 50, 200);

if (!tenantId) throw new Error('tenantId requis');

return [{ json: { tenantId, channel, minNote, limit } }];

parameters.query:
={{ (function() {
  var d = $json;
  var q = "SELECT a.id, a.nom, a.prenom, a.entreprise, a.email, a.telephone, a.note, a.commentaire, a.channel, a.affiche, a.token, a.lead_id, a.created_at "
    + "FROM avis a WHERE a.tenant_id = '" + d.tenantId + "'";
  if (d.channel) q += " AND a.channel = '" + d.channel + "'";
  if (d.minNote > 0) q += " AND a.note >= " + d.minNote;
  q += " ORDER BY a.created_at DESC LIMIT " + d.limit;
  return q;
})() }}

