var rows = $input.all().map(function(item) {
  var r = item.json;
  return {
    id: r.id,
    nom: r.nom,
    prenom: r.prenom,
    entreprise: r.entreprise,
    email: r.email,
    telephone: r.telephone,
    note: r.note,
    commentaire: r.commentaire,
    channel: r.channel,
    affiche: r.affiche,
    leadId: r.lead_id,
    token: r.token,
    createdAt: r.created_at
  };
});

// Stats
var total = rows.length;
var moyenneNote = total > 0 ? (rows.reduce(function(s, r) { return s + r.note; }, 0) / total).toFixed(1) : 0;
var parChannel = {};
rows.forEach(function(r) { parChannel[r.channel] = (parChannel[r.channel] || 0) + 1; });

return [{ json: { success: true, total: total, moyenneNote: parseFloat(moyenneNote), parChannel: parChannel, avis: rows } }];
